    static const std::unordered_map<std::wstring, std::wstring>& Index()
    {
        static const auto* m = []()
        {
            auto* out = new std::unordered_map<std::wstring, std::wstring>();
            out->reserve(sizeof(kTable) / sizeof(kTable[0]));
            for (const auto& e : kTable)
            {
                (*out)[e.reading] = e.preferred;
            }
            return out;
        }();
        return *m;
    }

    std::wstring GetPreferred(const std::wstring& reading)
    {
        const auto& m = Index();
        auto it = m.find(reading);
        return (it != m.end()) ? it->second : std::wstring{};
    }

    std::vector<std::wstring> PromoteToTop(const std::wstring& reading,
                                           std::vector<std::wstring> candidates)
    {
        std::wstring preferred = GetPreferred(reading);
        if (preferred.empty()) return candidates;
        if (!candidates.empty() && candidates[0] == preferred) return candidates;
        auto it = std::find(candidates.begin(), candidates.end(), preferred);
        if (it != candidates.end()) candidates.erase(it);
        candidates.insert(candidates.begin(), preferred);
        return candidates;
    }
